 namespace WPAICG\SEO\RankMath; if (!defined('ABSPATH')) { exit; } function update_focus_keyword_logic(int $post_id, string $keyword): bool { if (empty($post_id) || !is_string($keyword)) { return false; } $result = update_post_meta($post_id, 'rank_math_focus_keyword', sanitize_text_field($keyword)); return $result !== false; } 